(function () {
  function addStyle() { if (document.getElementById('fcp-style')) return; var s = document.createElement('style'); s.id = 'fcp-style'; s.textContent = '.fcp-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.fcp-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:12px}.fcp-panel{background:#f8fafc;border:1px solid #e5e7eb;border-radius:10px;padding:12px}.fcp-row{display:flex;align-items:center;justify-content:space-between;gap:8px;margin:8px 0}.fcp-row select{min-width:74px}.fcp-chip{display:inline-block;padding:4px 9px;border-radius:999px;background:#e8f4fd;border:1px solid #007bff;color:#174ea6;font-weight:700}.fcp-out{margin-top:12px;padding:12px;border-radius:8px;background:#d4edda;border-left:4px solid #28a745}.fcp-warn{background:#fff3cd;border-left-color:#ffc107}.fcp-inv{margin-top:10px;padding:10px;border-radius:8px;background:#f8f9fa}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.fcpMounted) return; host.dataset.fcpMounted = '1'; addStyle(); var D = ['1','2','3'], A = ['a','b','c'], B = ['x','y','z']; host.innerHTML = '<div class="fcp-wrap"><h4>🔁 Pipeline hàm hợp</h4><p>Chọn f: {1,2,3} → A và g: A → B. Kết quả (g∘f)(x) cập nhật tức thì.</p><div class="fcp-grid"><div class="fcp-panel"><strong>f: domain → A</strong><div data-f></div></div><div class="fcp-panel"><strong>g: A → B</strong><div data-g></div></div><div class="fcp-panel"><strong>(g∘f)(x)</strong><div data-c></div></div></div><label class="fcp-row" style="justify-content:flex-start"><input type="checkbox" data-inv> Hiện nghịch đảo của f nếu song ánh</label><div class="fcp-out"></div><div class="fcp-inv"></div></div>'; var f = {1:'a',2:'b',3:'c'}, g = {a:'x',b:'y',c:'z'}; function sel(vals, cur) { return '<select>' + vals.map(function (v) { return '<option' + (v === cur ? ' selected' : '') + '>' + v + '</option>'; }).join('') + '</select>'; } function bij() { return A.every(function (a) { return Object.keys(f).filter(function (x) { return f[x] === a; }).length === 1; }); } function paint() { host.querySelector('[data-f]').innerHTML = D.map(function (x) { return '<label class="fcp-row"><span><span class="fcp-chip">' + x + '</span> ↦</span>' + sel(A, f[x]) + '</label>'; }).join(''); host.querySelector('[data-g]').innerHTML = A.map(function (a) { return '<label class="fcp-row"><span><span class="fcp-chip">' + a + '</span> ↦</span>' + sel(B, g[a]) + '</label>'; }).join(''); host.querySelector('[data-c]').innerHTML = D.map(function (x) { return '<div class="fcp-row"><span>(g∘f)(' + x + ') = g(' + f[x] + ')</span><strong>' + g[f[x]] + '</strong></div>'; }).join(''); var ok = bij(), out = host.querySelector('.fcp-out'); out.className = 'fcp-out' + (ok ? '' : ' fcp-warn'); out.innerHTML = ok ? 'f là song ánh nên có f<sup>-1</sup>.' : 'f chưa song ánh: có giá trị A bị thiếu hoặc bị lặp.'; host.querySelector('.fcp-inv').innerHTML = host.querySelector('[data-inv]').checked && ok ? 'f<sup>-1</sup>: ' + A.map(function (a) { return a + ' ↦ ' + D.find(function (x) { return f[x] === a; }); }).join(', ') : 'Bật ô trên để xem nghịch đảo khi f song ánh.'; host.querySelectorAll('[data-f] select').forEach(function (e, i) { e.onchange = function () { f[D[i]] = e.value; paint(); }; }); host.querySelectorAll('[data-g] select').forEach(function (e, i) { e.onchange = function () { g[A[i]] = e.value; paint(); }; }); } host.querySelector('[data-inv]').onchange = paint; paint(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="function-composition-pipeline"]').forEach(mount); });
}());
